c
/* ❌ WRONG */
ssize_t n = recv(fd, buf, 4096, 0);
buf[n] = '\0';
parse(buf);  // may be incomplete!

/* ✅ CORRECT */
size_t total = 0;
while (total < buf_size - 1) {
ssize_t n = recv(fd, buf + total,
buf_size - 1 - total, 0);
if (n <= 0) return -1;
total += n;
buf[total] = '\0';
if (strstr(buf, "\r\n\r\n"))
return (ssize_t)total;  // done
}
return -1;  // buffer exhausted
